let find_by_id id =
  List.find_opt (fun (s : skill_record) -> s.id = id) all_skills

let contains_substr hay needle =
  let hlen = String.length hay and nlen = String.length needle in
  if nlen = 0 then true
  else if nlen > hlen then false
  else
    let found = ref false in
    for i = 0 to hlen - nlen do
      if String.sub hay i nlen = needle then found := true
    done;
    !found

let search query =
  let q = String.lowercase_ascii query in
  List.filter (fun (s : skill_record) ->
    let name_l = String.lowercase_ascii s.discipline.name in
    let desc_l = String.lowercase_ascii s.discipline.description in
    let id_l = String.lowercase_ascii s.id in
    contains_substr name_l q || contains_substr desc_l q || contains_substr id_l q
  ) all_skills
